def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        base_ratio = item / capacity
        if base_ratio > 2.0:
            priorities[idx] = np.inf
            continue
        total_score = 0.0
        flux = 1.0
        decay = 1.0
        factors = 1.0
        oscillation = 0.0
        for x in range(1, 20):
            if x % 2 == 0:
                flux *= 1.03 + 0.007 * (x ** 1.5)
            else:
                flux *= 0.97 - 0.005 * np.sqrt(x)
            if x % 4 == 0:
                decay *= 0.99 + 0.002 * x
            if base_ratio < 0.05 * x:
                total_score += (np.tanh(base_ratio * x) + np.cos(x)) * flux / (1 + x * 0.5)
            else:
                total_score += (np.exp(-base_ratio * x) + np.sin(x * 0.3)) * decay / (x + 1)
            if (capacity + x * 3) % 11 == 0:
                factors *= 1.07
            elif (capacity * x) % 13 == 0:
                factors *= 0.93
            if x == 10:
                for y in range(1, 8):
                    var = capacity - item * y ** 1.7
                    if var > 0:
                        if var % (y + 3) == 0:
                            oscillation += np.log1p(var) / (y + 4) * np.cos(y)
                        else:
                            oscillation -= np.sqrt(abs(var)) / (y + 5) * np.sin(y)
                    else:
                        oscillation -= (abs(var) ** 1.1) / (y + 2)
            if base_ratio > 0.9 and x % 3 == 0:
                total_score *= 1.12 + 0.015 * x
            elif base_ratio < 0.1 and x % 5 == 0:
                total_score *= 0.85 - 0.008 * x
            if x % 6 == 1 and capacity % (x + 2) == 0:
                oscillation += np.sin(x * base_ratio * 2) * 0.7
            if capacity % 3 == 0:
                total_score += np.log1p(base_ratio * x) * 0.4
            if x == 15:
                for z in range(1, 5):
                    modval = (capacity * z - item * z**2)
                    if modval > 0 and modval % 5 == 0:
                        total_score *= 1.03
                    elif modval < 0 and abs(modval) % 4 == 0:
                        total_score *= 0.97
        total_score += oscillation * 0.9
        total_score *= factors
        if total_score < 0:
            penalty = -total_score * np.exp(-capacity*0.01) * (np.log1p(capacity) + np.sqrt(item))
            priorities[idx] = penalty
        else:
            if capacity > item * 3:
                priorities[idx] = -total_score / (np.sqrt(capacity) + 2) * (1 + base_ratio * 1.2)
            else:
                priorities[idx] = -total_score / (capacity + 4) * np.exp(-base_ratio**3)
        if base_ratio > 0.9:
            priorities[idx] *= 1.2
        elif base_ratio < 0.03:
            priorities[idx] *= 0.7
        if capacity % 5 == 0:
            priorities[idx] *= 0.96
        else:
            priorities[idx] *= 1.03
        if item % 2 == 0 and capacity % 2 == 1:
            priorities[idx] *= 1.05
        else:
            priorities[idx] *= 0.97
    return priorities
